# Using MSAL Python for OIDC sign-in — handles discovery, PKCE, token cache
import msal, flask, os

app = flask.Flask(__name__)
app.secret_key = os.urandom(24)

TENANT_ID = "<your-tenant-id>"
CLIENT_ID = "<your-app-client-id>"
CLIENT_SECRET = "<your-app-secret>"
REDIRECT_URI  = "http://localhost:5000/callback"

msal_app = msal.ConfidentialClientApplication(
    CLIENT_ID,
    authority=f'https://login.microsoftonline.com/{TENANT_ID}',
    client_credential=CLIENT_SECRET,
)

@app.route('/login')
def login():
    # MSAL generates the auth URL with PKCE and state
    flow = msal_app.initiate_auth_code_flow(
        scopes=['openid', 'profile', 'email', 'User.Read'],
        redirect_uri=REDIRECT_URI,
    )
    flask.session['flow'] = flow
    return flask.redirect(flow['auth_uri'])

@app.route('/callback')
def callback():
    result = msal_app.acquire_token_by_auth_code_flow(
        flask.session.pop('flow'),
        flask.request.args,
    )
    if 'error' in result:
        return f'Auth error: {result["error_description"]}', 400

    # id_token_claims contains the validated ID token claims
    user = result['id_token_claims']
    flask.session['user'] = {
        'oid':   user['oid'],
        'name':  user.get('name'),
        'email': user.get('preferred_username'),
    }
    return flask.redirect('/')

@app.route('/logout')
def logout():
    flask.session.clear()
    # Redirect to Entra logout to clear the SSO session
    return flask.redirect(
        f'https://login.microsoftonline.com/{TENANT_ID}/oauth2/v2.0/logout'
        f'?post_logout_redirect_uri=http://localhost:5000'
    )

if __name__ == '__main__':
    app.run(debug=True)

# OIDC Security Checklist — common vulnerabilities and mitigations

# 1. CSRF on the redirect: validate state parameter
import secrets, flask

def start_login():
    state = secrets.token_urlsafe(32)
    flask.session['oauth_state'] = state
    # Include state in auth URL
    return redirect_to_auth(state=state)

def handle_callback(request_args):
    returned_state = request_args.get('state', '')
    stored_state   = flask.session.pop('oauth_state', None)
    if not secrets.compare_digest(returned_state, stored_state or ''):
        flask.abort(403, 'State mismatch — CSRF detected')

# 2. Replay attack on ID token: validate nonce
def start_login_with_nonce():
    nonce = secrets.token_urlsafe(32)
    flask.session['oidc_nonce'] = nonce
    return redirect_to_auth(nonce=nonce)

def validate_id_token_nonce(claims):
    expected = flask.session.pop('oidc_nonce', None)
    if not expected or not secrets.compare_digest(claims.get('nonce', ''), expected):
        raise ValueError('Nonce mismatch — ID token replay detected')

# 3. Confusion attack: ensure aud matches your client_id exactly
def check_audience(claims, expected_client_id: str):
    aud = claims.get('aud')
    if isinstance(aud, list):
        if expected_client_id not in aud:
            raise ValueError(f'Client ID {expected_client_id} not in aud list')
    elif aud != expected_client_id:
        raise ValueError(f'Token aud {aud!r} != expected {expected_client_id!r}')

# 4. Expired token accepted: always check exp
import time
def check_expiry(claims, leeway_seconds: int = 30):
    exp = claims.get('exp', 0)
    if time.time() > exp + leeway_seconds:
        raise ValueError(f'ID token expired at {exp}')

